function gerenciarMenu(){jQuery(window).width()<768?(jQuery("#menu").hide(),localStorage.setItem("abreMenu",1)):(jQuery("#menu").show(),localStorage.setItem("abreMenu",0),jQuery("#MenuHambruguer").hide())}console.log("Slick atribuições carregado"),jQuery(document).ready(function(){gerenciarMenu(),jQuery("#logosDasOperadorasHeader").slick({dots:!0,infinite:!0,speed:4e3,slidesToShow:2,slidesToScroll:1,autoplay:!0,autoplaySpeed:1e3,arrows:!1,responsive:[{breakpoint:786,settings:{slidesToShow:1,slidesToScroll:1}}]}),jQuery("#MenuHambruguer").click(function(){jQuery("#menu").addClass("menuAnda").show(),jQuery("#menu").children("#fundo").addClass("fundoMenu").show()}),jQuery("#fundo").click(function(){jQuery("#menu").hide()}),jQuery("#menu").children("ul").children("li").children("a").click(function(){jQuery("#menu").hide()})});